import { useState, useEffect } from "react";
import "./Recruitment.css";

function Designations() {
  const [title, setTitle] = useState("");
  const [list, setList] = useState([]);

  const [isEditing, setIsEditing] = useState(false);
  const [editId, setEditId] = useState(null);

  // Load data on page load
  useEffect(() => {
    const saved = JSON.parse(localStorage.getItem("designations")) || [];
    setList(saved);
  }, []);

  // Save to LocalStorage (Reusable Helper)
  const saveToStorage = (data) => {
    localStorage.setItem("designations", JSON.stringify(data));
  };

  // CREATE ROLE
  const handleCreate = () => {
    if (!title.trim()) return alert("Please enter designation");

    const exists = list.some(
      (d) => d.title.toLowerCase() === title.toLowerCase()
    );

    if (exists) return alert("This designation already exists");

    const newItem = {
      id: Date.now(),
      title,
    };

    const updated = [...list, newItem];
    setList(updated);
    saveToStorage(updated);

    setTitle("");
    alert("Designation Created Successfully");
  };

  // DELETE ROLE
  const handleDelete = (id) => {
    if (!window.confirm("Are you sure you want to delete this role?"))
      return;

    const updated = list.filter((d) => d.id !== id);
    setList(updated);
    saveToStorage(updated);
  };

  // START EDIT MODE
  const handleEdit = (designation) => {
    setIsEditing(true);
    setEditId(designation.id);
    setTitle(designation.title);
  };

  // SAVE EDIT
  const handleUpdate = () => {
    if (!title.trim()) return alert("Please enter designation");

    const exists = list.some(
      (d) =>
        d.title.toLowerCase() === title.toLowerCase() && d.id !== editId
    );

    if (exists) return alert("This designation already exists");

    const updated = list.map((d) =>
      d.id === editId ? { ...d, title } : d
    );

    setList(updated);
    saveToStorage(updated);

    setIsEditing(false);
    setEditId(null);
    setTitle("");

    alert("Designation Updated Successfully");
  };

  // CANCEL EDIT
  const cancelEdit = () => {
    setIsEditing(false);
    setEditId(null);
    setTitle("");
  };

  return (
    <div className="designation-container">
      <h2>Generate Employee Designation</h2>

      {/* Input + Button */}
      <div className="designation-form">
        <input
          type="text"
          placeholder="Enter Designation e.g Manager"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
        />

        {!isEditing ? (
          <button onClick={handleCreate}>
            Create
          </button>
        ) : (
          <>
            <button onClick={handleUpdate} style={{ background: "#2563eb" }}>
              Update
            </button>

            <button
              onClick={cancelEdit}
              style={{ background: "gray" }}
            >
              Cancel
            </button>
          </>
        )}
      </div>

      {/* TABLE */}
      <table className="designation-table">
        <thead>
          <tr>
            <th>S.No</th>
            <th>Designation Title</th>
            <th>Action</th>
          </tr>
        </thead>

        <tbody>
          {list.length === 0 ? (
            <tr>
              <td colSpan="3">No Designations Created Yet</td>
            </tr>
          ) : (
            list.map((d, index) => (
              <tr key={d.id}>
                <td>{index + 1}</td>
                <td>{d.title}</td>

                <td>
                  <button
                    className="edit-btn"
                    onClick={() => handleEdit(d)}
                  >
                    Edit
                  </button>

                  <button
                    className="delete-btn"
                    onClick={() => handleDelete(d.id)}
                  >
                    Delete
                  </button>
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
}

export default Designations;
